from dataclasses import dataclass@dataclass(slots=True)class Detector:    """    CRIRES+ detector within a single echelle order.    Parameters    ----------    number : int        Detector number (1–3).    wavelength_min : float        Minimum wavelength covered by the detector (μm).    wavelength_max : float        Maximum wavelength covered by the detector (μm).    """    number: int    wavelength_min: float    wavelength_max: float        # properties        @property    def width(self) -> float:        """Detector wavelength coverage in μm."""        return self.wavelength_max - self.wavelength_min    @property    def wavelength_center(self) -> float:        """Central wavelength of the detector."""        return 0.5 * (            self.wavelength_min +            self.wavelength_max        )    @property    def wavelengths_range(self):        """Minimum and maximum detector wavelength."""        return (            self.wavelength_min,            self.wavelength_max,        )        # public methods        def __contains__(self, wavelength: float) -> bool:        """Return whether a wavelength falls on this detector."""        return (            self.wavelength_min            <= wavelength            <= self.wavelength_max        )        # dunder methods        def __str__(self):        return (            f"Detector {self.number}: "            f"{self.wavelength_min:.3f}–"            f"{self.wavelength_max:.3f} μm"        )    